#define SCORE(i, j) input_itemsets_l[(j) + (i) * (BLOCK_SIZE + 1)]
#define REF(i, j)   reference_l[(j) + (i) * BLOCK_SIZE]

__device__ __forceinline__ int maximum(int a, int b, int c) {
	int k;
	if (a <= b)
		k = b;
	else
		k = a;

	if (k <= c)
		return c;
	else
